function classify(n) {
  if (n > 0) return "positive";
  else if (n < 0) return "negative";
  else return "zero";
}

medium.solution:
function isLeap(year) {
  if (year % 400 === 0) return true;
  else if (year % 100 === 0) return false;
  else if (year % 4 === 0) return true;
  else return false;
}

